mapper.select:
SELECT COUNT(1)
FROM agent_run_log


        AND tool_name = #{toolName}


        AND success = #{success}

SELECT id, trace_id, user_message, answer, used_tool, tool_name, decision_cost_ms, tool_cost_ms, summary_cost_ms, agent_cost_ms, success, error_message, created_time FROM agent_run_log
AND tool_name = #{toolName}
AND success = #{success}
ORDER BY created_time DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(1) AS total, COALESCE(SUM(CASE WHEN success = 1 THEN 1 ELSE 0 END), 0) AS successCount, COALESCE(SUM(CASE WHEN success = 0 THEN 1 ELSE 0 END), 0) AS failedCount, ROUND(AVG(decision_cost_ms), 2) AS avgDecisionCostMs, ROUND(AVG(tool_cost_ms), 2) AS avgToolCostMs, ROUND(AVG(summary_cost_ms), 2) AS avgSummaryCostMs, ROUND(AVG(agent_cost_ms), 2) AS avgAgentCostMs FROM agent_run_log
AND tool_name = #{toolName}
AND success = #{success}

SELECT COALESCE(tool_name, 'NO_TOOL') AS toolName, COUNT(1) AS runCount, ROUND(AVG(agent_cost_ms), 2) AS avgAgentCostMs, ROUND(AVG(tool_cost_ms), 2) AS avgToolCostMs, MAX(agent_cost_ms) AS maxAgentCostMs FROM agent_run_log
AND tool_name = #{toolName}
AND success = #{success}
GROUP BY COALESCE(tool_name, 'NO_TOOL') ORDER BY runCount DESC
